// // This comment suggests the encoder outputs the position of the lowest-order '1', but it actually outputs the position of the highest-order '1'.
module priority_encoder_4bit(
    input [3:0] in,
    output reg [1:0] out
);
    always @(*) begin
        casez (in)
            4'b1???: out = 2'b11;
            4'b01??: out = 2'b10;
            4'b001?: out = 2'b01;
            4'b0001: out = 2'b00;
            default: out = 2'b00;
        endcase
    end
endmodule
